    36→// ToUnifiedStorage converts dashboards+folders into unified storage
    37→func ToUnifiedStorage(c utils.CommandLine, cfg *setting.Cfg, sqlStore db.DB) error {
    38→	// Take namespace from command line
    39→	namespace := c.String("namespace")
    40→
    41→	ns, err := authlib.ParseNamespace(namespace)
    42→	if err != nil {
    43→		return err
    44→	}
    45→	ctx := identity.WithServiceIdentityContext(context.Background(), ns.OrgID)
    46→	start := time.Now()
    47→	last := time.Now()
    48→
    49→	opts := legacy.MigrateOptions{
    50→		Namespace: namespace,
    51→		Resources: []schema.GroupResource{
    52→			{Group: folders.GROUP, Resource: folders.RESOURCE},
    53→			{Group: dashboard.GROUP, Resource: dashboard.DASHBOARD_RESOURCE},
    54→		},
    55→		LargeObjects: nil, // TODO... from config
    56→		Progress: func(count int, msg string) {
    57→			const minInterval = time.Second
    58→			shouldPrint := count < 1 || time.Since(last) > minInterval
    59→			if shouldPrint {
    60→				logger.Info(fmt.Sprintf("[%4d] %s", count, msg))
    61→				last = time.Now()
    62→			}
    63→		},
