    59→	}
    60→
    61→	return &apimodels.PostableApiReceiver{
    62→		Receiver: alertingNotify.ConfigReceiver{
    63→			Name: r.Name,
    64→		},
    65→		PostableGrafanaReceivers: integrations,
    66→	}, nil
    67→}
