    69→func PostableApiReceiverToReceiver(postable *apimodels.PostableApiReceiver, provenance models.Provenance, origin models.ResourceOrigin) (*models.Receiver, error) {
    70→	integrations, err := PostableGrafanaReceiversToIntegrations(postable.GrafanaManagedReceivers)
    71→	if err != nil {
    72→		return nil, err
    73→	}
    74→	r := &models.Receiver{
    75→		UID:          NameToUid(postable.GetName()), // TODO replace with stable UID.
    76→		Name:         postable.GetName(),
    77→		Integrations: integrations,
    78→		Provenance:   provenance,
