    85→// GetReceiverProvenance determines the provenance of a definitions.PostableApiReceiver based on the provenance of its integrations.
    86→func GetReceiverProvenance(storedProvenances map[string]models.Provenance, r *apimodels.PostableApiReceiver, origin models.ResourceOrigin) models.Provenance {
    87→	if origin == models.ResourceOriginImported {
    88→		return models.ProvenanceConvertedPrometheus
    89→	}
    90→
    91→	if len(r.GrafanaManagedReceivers) == 0 || len(storedProvenances) == 0 {
    92→		return models.ProvenanceNone
    93→	}
    94→
    95→	// Current provisioning works on the integration level, so we need some way to determine the provenance of the
    96→	// entire receiver. All integrations in a receiver should have the same provenance, but we don't want to rely on
    97→	// this assumption in case the first provenance is None and a later one is not. To this end, we return the first
    98→	// non-zero provenance we find.
    99→	for _, contactPoint := range r.GrafanaManagedReceivers {
   100→		if p, exists := storedProvenances[contactPoint.UID]; exists && p != models.ProvenanceNone {
   101→			return p
   102→		}
   103→	}
   104→	return models.ProvenanceNone
   105→}
