   107→func PostableGrafanaReceiversToIntegrations(postables []*apimodels.PostableGrafanaReceiver) ([]*models.Integration, error) {
   108→	integrations := make([]*models.Integration, 0, len(postables))
   109→	for _, cfg := range postables {
   110→		integration, err := PostableGrafanaReceiverToIntegration(cfg)
   111→		if err != nil {
   112→			return nil, err
   113→		}
   114→		integrations = append(integrations, integration)
