   120→func PostableGrafanaReceiverToIntegration(p *apimodels.PostableGrafanaReceiver) (*models.Integration, error) {
   121→	integrationType, err := alertingNotify.IntegrationTypeFromString(p.Type)
   122→	if err != nil {
   123→		return nil, err
   124→	}
   125→	config, ok := alertingNotify.GetSchemaVersionForIntegration(integrationType, schema.V1)
   126→	if !ok {
   127→		return nil, fmt.Errorf("integration type [%s] does not have schema of version %s", integrationType, schema.V1)
   128→	}
   129→	integration := &models.Integration{
   130→		UID:                   p.UID,
   131→		Name:                  p.Name,
   132→		Config:                config,
   133→		DisableResolveMessage: p.DisableResolveMessage,
   134→		Settings:              make(map[string]any, len(p.Settings)),
   135→		SecureSettings:        make(map[string]string, len(p.SecureSettings)),
   136→	}
   137→
   138→	if p.Settings != nil {
   139→		if err := json.Unmarshal(p.Settings, &integration.Settings); err != nil {
   140→			return nil, fmt.Errorf("integration '%s' of receiver '%s' has settings that cannot be parsed as JSON: %w", integration.Config.Type(), p.Name, err)
   141→		}
   142→	}
